const now = new Date();
// Hora en Lima (UTC-5)
const limaOffset = -5 * 60;
const limaTime = new Date(now.getTime() + (limaOffset + now.getTimezoneOffset()) * 60000);
const hour = limaTime.getHours();
const turno = hour < 13 ? 'manana' : 'tarde';
const fecha = limaTime.toISOString().split('T')[0];
const session_id = `sess_${fecha}_${turno}_${Math.random().toString(36).substr(2,5)}`;

return [{ json: { turno, fecha, hora_lima: hour, session_id } }];

const rows = $input.all();
const titulos_publicados = rows
  .map(r => (r.json.elegida_title || '').toLowerCase().trim())
  .filter(t => t.length > 0);

// Pasar al contexto global via output
const turno_data = $('Detectar.Turno').first().json;
return [{
  json: {
    turno: turno_data.turno,
    fecha: turno_data.fecha,
    session_id: turno_data.session_id,
    titulos_publicados,
    max_opciones: 4  // tarde siempre muestra 4
  }
}];

// Unificar contexto de turno mañana y tarde en un solo item
const turno_data = $('Detectar.Turno').first().json;
// Si llegamos aquí desde mañana, no hay publicadas
return [{
  json: {
    turno: turno_data.turno,
    fecha: turno_data.fecha,
    session_id: turno_data.session_id,
    titulos_publicados: [],
    max_opciones: 5  // mañana muestra 5
  }
}];

const items = $input.all();
return items.map(item => {
  let out = {};
  try { out = item.json.output || {}; } catch(e) {}
  return { json: {
    title:      item.json.title,
    link:       item.json.link,
    snippet:    item.json.snippet,
    pubDate:    item.json.pubDate,
    score:      out.score  || 0,
    nivel:      out.nivel  || 'bajo',
    razon:      out.razon  || '',
    angulo:     out.angulo_viral || '',
    emoji:      out.emoji_clave || '📰',
    categoria:  out.categoria || 'otro',
  }};
});

const items = $input.all();
// Leer contexto de turno desde Merge.Contexto
const ctx = $('Merge.Contexto').first().json;
const titulos_publicados = ctx.titulos_publicados || [];
const max_opciones = ctx.max_opciones || 5;
const session_id   = ctx.session_id;
const turno        = ctx.turno;
const fecha        = ctx.fecha;

// Ordenar por score
const sorted = [...items].sort((a, b) => b.json.score - a.json.score);

// Excluir noticias ya publicadas hoy
const disponibles = sorted.filter(item => {
  const titulo = (item.json.title || '').toLowerCase().trim();
  return !titulos_publicados.some(pub => {
    // Comparación flexible: si comparten más del 60% del título
    if (!pub || !titulo) return false;
    const wordsA = titulo.split(' ');
    const wordsB = pub.split(' ');
    const matches = wordsA.filter(w => w.length > 4 && wordsB.includes(w)).length;
    return matches >= 2;
  });
});

const top = disponibles.slice(0, max_opciones);

if (!top.length) throw new Error('No hay noticias disponibles con score suficiente.');

const noticias = top.map((item, i) => ({
  index:    i + 1,
  title:    item.json.title,
  link:     item.json.link,
  snippet:  item.json.snippet,
  score:    item.json.score,
  nivel:    item.json.nivel,
  razon:    item.json.razon,
  angulo:   item.json.angulo,
  emoji:    item.json.emoji,
  categoria: item.json.categoria,
}));

return [{ json: { session_id, turno, fecha, noticias, total: noticias.length } }];

const data     = $('Seleccionar.TopN').first().json;
const session_id = data.session_id;
const noticias   = data.noticias;
const turno      = data.turno;
const turno_label = turno === 'manana' ? '🌅 MAÑANA' : '🌆 TARDE';
const top_label   = turno === 'manana' ? 'TOP 5' : 'TOP 4';

const escape = t => (t||'').replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&');

const messages = noticias.map((n) => {
  const stars  = '⭐'.repeat(Math.min(5, Math.floor(n.score / 20)));
  const cb_raw = JSON.stringify({ session_id, index: n.index, action: 'elegir' });
  // Telegram limita callback_data a 64 bytes → usamos ID corto
  const cb_short = JSON.stringify({ s: session_id.split('_').pop(), i: n.index, a: 'e' });

  return { json: {
    chatId: '1704819492',
    text: `${n.emoji} *Opción ${n.index} — Score ${n.score}/100 ${stars}*
` +
          `*${escape(n.title)}*

` +
          `💡 ${n.razon}
` +
          `🎯 ${n.angulo}
` +
          `🔗 ${n.link}`,
    session_id, noticia_index: n.index, es_intro: false,
    inline_keyboard: JSON.stringify({ inline_keyboard: [[
      { text: `✅ Elegir opción ${n.index}`, callback_data: cb_short.substring(0,64) }
    ]]})
  }};
});

const intro = { json: {
  chatId: '1704819492',
  text: `🗞️ *${turno_label} — ${top_label} NOTICIAS*
_Elige la que quieres publicar:_

📌 Session: \`${session_id}\``,
  es_intro: true, session_id, inline_keyboard: null
}};

return [intro, ...messages];

